# ===== BACKEND SCRIPT (before_save hook) =====

def today_str():
    return frappe.utils.today()

def parse_date(date_str):
    return frappe.utils.getdate(date_str)

# ===== GROSS MISCONDUCT CHECK =====
if doc.custom_is_gross_misconduct:
    doc.warning_level = "Summary Dismissal"
else:
    # Get previous warnings (only submitted records)
    previous_warnings = frappe.get_all(
        "Disciplinary",
        filters={
            "employee": doc.employee,
            "docstatus": 1,
            "name": ["!=", doc.name]
        },
        fields=["warning_level", "date_of_offense"],
        order_by="date_of_offense desc"
    )

    # ===== AUTO-GENERATE SUMMARY DISMISSAL IF FINAL WARNING EXISTS =====
    if previous_warnings:
        last_warning = previous_warnings[0]
        if last_warning.get("warning_level") == "Final Warning":
            doc.warning_level = "Summary Dismissal"

    # If no previous submitted warnings, set to First Warning
    if not previous_warnings and not doc.warning_level:
        doc.warning_level = "First Warning"

    # ===== VALIDATION: Check warning level sequence =====
    if previous_warnings:
        warning_order = {
            "First Warning": 1,
            "Second Warning": 2,
            "Final Warning": 3,
            "Summary Dismissal": 4
        }
        last = previous_warnings[0]
        last_level = warning_order.get(last.get("warning_level"), 0)
        current_level = warning_order.get(doc.get("warning_level"), 0)
        expected_level = last_level + 1

        # Prevent issuing a lower-level warning than the last one
        if current_level < expected_level:
            frappe.throw(
                "Warning level cannot be lower than the previous warning. "
                f"Last warning was {last.get('warning_level')}"
            )

        # Inform if skipping levels
        if current_level > expected_level:
            frappe.msgprint(
                f"You are skipping warning levels. Last warning was {last.get('warning_level')}, "
                f"you are issuing {doc.get('warning_level')}.",
                indicator="red"
            )

# Validate that date_of_offense is not in the future
if doc.date_of_offense:
    if parse_date(doc.date_of_offense) > parse_date(today_str()):
        frappe.throw("Date of Offense cannot be in the future.")
